import{_ as s,o as a,c as t,ag as n}from"./chunks/framework.DXGyWiRo.js";const h=JSON.parse('{"title":"Data Sizes & Storage Calculations","description":"","frontmatter":{},"headers":[],"relativePath":"practical/number-systems/data-sizes.md","filePath":"practical/number-systems/data-sizes.md"}'),i={name:"practical/number-systems/data-sizes.md"};function r(l,e,p,d,o,c){return a(),t("div",null,[...e[0]||(e[0]=[n(`<h1 id="data-sizes-storage-calculations" tabindex="-1">Data Sizes &amp; Storage Calculations <a class="header-anchor" href="#data-sizes-storage-calculations" aria-label="Permalink to &quot;Data Sizes &amp; Storage Calculations&quot;">​</a></h1><p>Understanding data sizes lets you answer questions like: &quot;How much storage does this image need?&quot; or &quot;How long will this file take to download?&quot; These calculations appear in both Paper 1 and Paper 2.</p><div class="note custom-block github-alert"><p class="custom-block-title">Grade 10+</p><p>Data sizes and storage calculations are introduced in Grade 10. The calculation method is the same every time — practise it until it is automatic.</p></div><hr><h2 id="the-units" tabindex="-1">The Units <a class="header-anchor" href="#the-units" aria-label="Permalink to &quot;The Units&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Unit</th><th>Abbreviation</th><th>Size</th><th>Power of 2</th></tr></thead><tbody><tr><td>Bit</td><td>b</td><td>1 binary digit (0 or 1)</td><td>—</td></tr><tr><td>Nibble</td><td>—</td><td>4 bits</td><td>2²</td></tr><tr><td>Byte</td><td>B</td><td>8 bits</td><td>2³</td></tr><tr><td>Kilobyte</td><td>KB</td><td>1 024 bytes</td><td>2¹⁰</td></tr><tr><td>Megabyte</td><td>MB</td><td>1 024 KB</td><td>2²⁰</td></tr><tr><td>Gigabyte</td><td>GB</td><td>1 024 MB</td><td>2³⁰</td></tr><tr><td>Terabyte</td><td>TB</td><td>1 024 GB</td><td>2⁴⁰</td></tr><tr><td>Petabyte</td><td>PB</td><td>1 024 TB</td><td>2⁵⁰</td></tr></tbody></table><div class="warning custom-block github-alert"><p class="custom-block-title">1 KB = 1 024, NOT 1 000</p><p>In computing, prefixes are powers of 2. Manufacturers sometimes use 1 000 (metric), which is why a &quot;500 GB&quot; hard drive shows as ~465 GB in Windows. In IT exams, always use 1 024.</p></div><h3 id="quick-scale" tabindex="-1">Quick Scale <a class="header-anchor" href="#quick-scale" aria-label="Permalink to &quot;Quick Scale&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>8 bits = 1 byte</span></span>
<span class="line"><span>1 024 bytes = 1 KB</span></span>
<span class="line"><span>1 024 KB    = 1 MB</span></span>
<span class="line"><span>1 024 MB    = 1 GB</span></span>
<span class="line"><span>1 024 GB    = 1 TB</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><hr><h2 id="converting-between-units" tabindex="-1">Converting Between Units <a class="header-anchor" href="#converting-between-units" aria-label="Permalink to &quot;Converting Between Units&quot;">​</a></h2><h3 id="larger-→-smaller-multiply" tabindex="-1">Larger → Smaller (multiply) <a class="header-anchor" href="#larger-→-smaller-multiply" aria-label="Permalink to &quot;Larger → Smaller (multiply)&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GB → MB: × 1 024</span></span>
<span class="line"><span>MB → KB: × 1 024</span></span>
<span class="line"><span>KB → B:  × 1 024</span></span>
<span class="line"><span>B  → bits: × 8</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p><strong>Example:</strong> Convert 2.5 MB to bytes:<br> 2.5 × 1 024 = 2 560 KB<br> 2 560 × 1 024 = 2 621 440 bytes</p><h3 id="smaller-→-larger-divide" tabindex="-1">Smaller → Larger (divide) <a class="header-anchor" href="#smaller-→-larger-divide" aria-label="Permalink to &quot;Smaller → Larger (divide)&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>bytes → KB: ÷ 1 024</span></span>
<span class="line"><span>KB → MB: ÷ 1 024</span></span>
<span class="line"><span>MB → GB: ÷ 1 024</span></span>
<span class="line"><span>bits → bytes: ÷ 8</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p><strong>Example:</strong> Convert 5 120 bytes to KB:<br> 5 120 ÷ 1 024 = <strong>5 KB</strong></p><hr><h2 id="storage-calculation-method" tabindex="-1">Storage Calculation Method <a class="header-anchor" href="#storage-calculation-method" aria-label="Permalink to &quot;Storage Calculation Method&quot;">​</a></h2><p>The general method for finding how much storage a file needs:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. Find the number of items (characters, pixels, samples, etc.)</span></span>
<span class="line"><span>2. Find how many bits each item needs</span></span>
<span class="line"><span>3. Multiply: total bits = items × bits per item</span></span>
<span class="line"><span>4. Convert to bytes: total bits ÷ 8</span></span>
<span class="line"><span>5. Convert to KB/MB as required: ÷ 1 024 per step</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><hr><h2 id="text-files" tabindex="-1">Text Files <a class="header-anchor" href="#text-files" aria-label="Permalink to &quot;Text Files&quot;">​</a></h2><p><strong>Rule:</strong> In ASCII, 1 character = 1 byte (8 bits).</p><h3 id="example-1-—-plain-text-file" tabindex="-1">Example 1 — Plain text file <a class="header-anchor" href="#example-1-—-plain-text-file" aria-label="Permalink to &quot;Example 1 — Plain text file&quot;">​</a></h3><p>A text file contains 8 000 characters. How much storage (in KB)?</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>8 000 characters × 1 byte = 8 000 bytes</span></span>
<span class="line"><span>8 000 ÷ 1 024 = 7.81 KB ≈ 7.8 KB</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h3 id="example-2-—-word-document" tabindex="-1">Example 2 — Word document <a class="header-anchor" href="#example-2-—-word-document" aria-label="Permalink to &quot;Example 2 — Word document&quot;">​</a></h3><p>A book has 350 pages. Each page has 40 lines, each line has 70 characters. Storage needed (in MB)?</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>350 × 40 × 70 = 980 000 characters</span></span>
<span class="line"><span>980 000 × 1 byte = 980 000 bytes</span></span>
<span class="line"><span>980 000 ÷ 1 024 = 957.03 KB</span></span>
<span class="line"><span>957.03 ÷ 1 024 = 0.935 MB ≈ 0.9 MB</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><hr><h2 id="images-uncompressed-bitmap" tabindex="-1">Images (Uncompressed/Bitmap) <a class="header-anchor" href="#images-uncompressed-bitmap" aria-label="Permalink to &quot;Images (Uncompressed/Bitmap)&quot;">​</a></h2><p><strong>Key variables:</strong></p><ul><li><strong>Resolution</strong> = width × height (in pixels)</li><li><strong>Colour depth</strong> = bits per pixel</li></ul><p><strong>Formula:</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Storage = width × height × colour_depth_bits ÷ 8 (for bytes)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="colour-depth-reference" tabindex="-1">Colour Depth Reference <a class="header-anchor" href="#colour-depth-reference" aria-label="Permalink to &quot;Colour Depth Reference&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Colour depth</th><th>Colours possible</th><th>Storage per pixel</th></tr></thead><tbody><tr><td>1-bit</td><td>2 (black &amp; white)</td><td>1 bit</td></tr><tr><td>4-bit</td><td>16</td><td>4 bits = 0.5 byte</td></tr><tr><td>8-bit</td><td>256</td><td>1 byte</td></tr><tr><td>16-bit</td><td>65 536</td><td>2 bytes</td></tr><tr><td>24-bit</td><td>16 777 216 (True colour)</td><td>3 bytes</td></tr><tr><td>32-bit</td><td>16 777 216 + transparency</td><td>4 bytes</td></tr></tbody></table><h3 id="example-—-bitmap-image" tabindex="-1">Example — Bitmap Image <a class="header-anchor" href="#example-—-bitmap-image" aria-label="Permalink to &quot;Example — Bitmap Image&quot;">​</a></h3><p>A 24-bit colour photograph is 1920 × 1080 pixels. What is the file size in MB?</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Pixels = 1 920 × 1 080 = 2 073 600</span></span>
<span class="line"><span>Bits = 2 073 600 × 24 = 49 766 400 bits</span></span>
<span class="line"><span>Bytes = 49 766 400 ÷ 8 = 6 220 800 bytes</span></span>
<span class="line"><span>KB = 6 220 800 ÷ 1 024 = 6 075 KB</span></span>
<span class="line"><span>MB = 6 075 ÷ 1 024 = 5.93 MB ≈ 5.9 MB</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><div class="note custom-block github-alert"><p class="custom-block-title">Compression Reduces This</p><p>A JPEG of the same photograph might be 500 KB after compression. The uncompressed calculation gives the raw/bitmap size — the question will specify whether to calculate uncompressed or account for compression.</p></div><hr><h2 id="audio-files-uncompressed" tabindex="-1">Audio Files (Uncompressed) <a class="header-anchor" href="#audio-files-uncompressed" aria-label="Permalink to &quot;Audio Files (Uncompressed)&quot;">​</a></h2><p><strong>Key variables:</strong></p><ul><li><strong>Sample rate</strong> = samples per second (Hz or kHz): CD quality = 44 100 Hz</li><li><strong>Bit depth</strong> = bits per sample: CD quality = 16 bits</li><li><strong>Channels</strong>: mono = 1, stereo = 2</li><li><strong>Duration</strong>: in seconds</li></ul><p><strong>Formula:</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Storage = sample_rate × bit_depth × channels × duration_seconds ÷ 8</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="example-—-audio-recording" tabindex="-1">Example — Audio Recording <a class="header-anchor" href="#example-—-audio-recording" aria-label="Permalink to &quot;Example — Audio Recording&quot;">​</a></h3><p>A 3-minute stereo recording at 44 100 Hz, 16-bit. Size in MB?</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Duration = 3 × 60 = 180 seconds</span></span>
<span class="line"><span>Bits = 44 100 × 16 × 2 × 180 = 254 016 000 bits</span></span>
<span class="line"><span>Bytes = 254 016 000 ÷ 8 = 31 752 000 bytes</span></span>
<span class="line"><span>KB = 31 752 000 ÷ 1 024 = 31 007.8 KB</span></span>
<span class="line"><span>MB = 31 007.8 ÷ 1 024 = 30.3 MB</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><hr><h2 id="video-files-uncompressed" tabindex="-1">Video Files (Uncompressed) <a class="header-anchor" href="#video-files-uncompressed" aria-label="Permalink to &quot;Video Files (Uncompressed)&quot;">​</a></h2><p><strong>Formula:</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Storage = frame_rate × duration × frame_size</span></span>
<span class="line"><span>frame_size = width × height × colour_depth_bits ÷ 8</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h3 id="example-—-short-video-clip" tabindex="-1">Example — Short Video Clip <a class="header-anchor" href="#example-—-short-video-clip" aria-label="Permalink to &quot;Example — Short Video Clip&quot;">​</a></h3><p>A 30-second video at 30 fps, 1280 × 720 resolution, 24-bit colour. Size in MB?</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Frame size = 1280 × 720 × 24 ÷ 8 = 2 764 800 bytes</span></span>
<span class="line"><span>Total frames = 30 × 30 = 900 frames</span></span>
<span class="line"><span>Total = 2 764 800 × 900 = 2 488 320 000 bytes</span></span>
<span class="line"><span>MB = 2 488 320 000 ÷ 1 024 ÷ 1 024 = 2 373 MB ≈ 2.3 GB</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>This is why video compression (MP4, HEVC) is essential.</p><hr><h2 id="data-transmission" tabindex="-1">Data Transmission <a class="header-anchor" href="#data-transmission" aria-label="Permalink to &quot;Data Transmission&quot;">​</a></h2><p><strong>Bandwidth</strong> is typically measured in <strong>bits per second</strong> (bps, Kbps, Mbps, Gbps).<br> Note: bandwidth uses lowercase &#39;b&#39; for bits; storage uses uppercase &#39;B&#39; for bytes.</p><p><strong>Formula:</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Transfer time = file_size_in_bits ÷ bandwidth_in_bps</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="example-—-download-time" tabindex="-1">Example — Download Time <a class="header-anchor" href="#example-—-download-time" aria-label="Permalink to &quot;Example — Download Time&quot;">​</a></h3><p>How long to download a 50 MB file on a 10 Mbps connection?</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>File size in bits = 50 × 1 024 × 1 024 × 8 = 419 430 400 bits</span></span>
<span class="line"><span>Bandwidth = 10 × 1 000 000 = 10 000 000 bps  (note: Mbps uses 1 000 000)</span></span>
<span class="line"><span>Time = 419 430 400 ÷ 10 000 000 = 41.9 seconds</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><div class="note custom-block github-alert"><p class="custom-block-title">Mbps Uses 1 000 000, not 1 048 576</p><p>Network speeds use SI prefixes (1 Mbps = 1 000 000 bps), not binary prefixes. Storage uses binary (1 MB = 1 048 576 bytes). This is a deliberate difference — don&#39;t mix them up.</p></div><hr><h2 id="quick-reference-—-steps-summary" tabindex="-1">Quick Reference — Steps Summary <a class="header-anchor" href="#quick-reference-—-steps-summary" aria-label="Permalink to &quot;Quick Reference — Steps Summary&quot;">​</a></h2><table tabindex="0"><thead><tr><th>File Type</th><th>Items</th><th>× Per Item</th><th>÷ 8</th><th>÷ 1024 per level</th></tr></thead><tbody><tr><td>Text (ASCII)</td><td>characters</td><td>8 bits</td><td>→ bytes</td><td>→ KB → MB</td></tr><tr><td>Image</td><td>width × height pixels</td><td>colour depth bits</td><td>→ bytes</td><td>→ KB → MB</td></tr><tr><td>Audio</td><td>sample_rate × channels × seconds</td><td>bit depth</td><td>→ bytes</td><td>→ KB → MB</td></tr><tr><td>Video</td><td>fps × seconds × pixels</td><td>colour depth bits</td><td>→ bytes</td><td>→ KB → MB → GB</td></tr></tbody></table><hr><h2 id="practice-exercises" tabindex="-1">Practice Exercises <a class="header-anchor" href="#practice-exercises" aria-label="Permalink to &quot;Practice Exercises&quot;">​</a></h2><p><strong>Exercise 1</strong></p><p>A school database stores 2 000 student records. Each record contains:</p><ul><li>30 characters for name</li><li>13 characters for ID number</li><li>3 characters for grade</li></ul><p>What is the total storage required in KB?</p><details><summary>Show solution</summary><p>Characters per record = 30 + 13 + 3 = 46 characters<br> Total characters = 2 000 × 46 = 92 000 characters<br> Bytes = 92 000 × 1 = 92 000 bytes (ASCII: 1 char = 1 byte)<br> KB = 92 000 ÷ 1 024 = <strong>89.8 KB ≈ 90 KB</strong></p></details><hr><p><strong>Exercise 2</strong></p><p>An 8-bit grayscale image is 800 × 600 pixels. What is its uncompressed file size in KB?</p><details><summary>Show solution</summary><p>Pixels = 800 × 600 = 480 000<br> Bits per pixel = 8 (8-bit colour depth)<br> Total bits = 480 000 × 8 = 3 840 000 bits<br> Bytes = 3 840 000 ÷ 8 = 480 000 bytes<br> KB = 480 000 ÷ 1 024 = <strong>468.75 KB ≈ 469 KB</strong></p></details><hr><p><strong>Exercise 3</strong></p><p>A podcast is recorded in mono at 22 050 Hz with 16-bit audio. The episode is 45 minutes long. Calculate the file size in MB.</p><details><summary>Show solution</summary><p>Duration = 45 × 60 = 2 700 seconds<br> Bits = 22 050 × 16 × 1 × 2 700 = 952 560 000 bits<br> Bytes = 952 560 000 ÷ 8 = 119 070 000 bytes<br> KB = 119 070 000 ÷ 1 024 = 116 279 KB<br> MB = 116 279 ÷ 1 024 = <strong>113.6 MB</strong></p></details><hr><div class="tip custom-block github-alert"><p class="custom-block-title">Exam Tip</p><p>Always show all your working in data-size questions — method marks are awarded even if you get the final answer wrong. Write each step clearly: total items, × bits per item, ÷ 8 for bytes, then ÷ 1024 for each level up. The formula is always the same — the question just changes which file type you&#39;re calculating.</p></div>`,88)])])}const u=s(i,[["render",r]]);export{h as __pageData,u as default};
